const contacts = $input.all();
const config = $('Client Config').item.json;
const today = new Date();
const staleThreshold = config.stale_threshold_days || 14;

const stale = [], active = [], engaged = [];

contacts.forEach(c => {
  const p = c.json;
  const lastActivity = p.last_activity_date ? new Date(p.last_activity_date) : null;
  const daysSince = lastActivity
    ? Math.floor((today - lastActivity) / (1000 * 60 * 60 * 24))
    : 99;

  const entry = {
    name: p.full_name || 'Unknown',
    company: p.company || 'Unknown',
    title: p.title || '',
    status: p.lead_status,
    score: p.icp_score,
    daysSince,
    contact_id: p.contact_id
  };

  if (daysSince >= staleThreshold) stale.push(entry);
  else if (p.lead_status === 'CONNECTED') engaged.push(entry);
  else active.push(entry);
});

const fmt = (list) => list.slice(0, 8).map((c, i) =>
  `  ${i+1}. ${c.name} — ${c.title} @ ${c.company} [${c.status}] (${c.daysSince}d since activity)`
).join('\n') || '  None';

const body = `Good morning ${config.recipient_name},

Friday Pipeline Report — ${today.toDateString()}

━━━━━━━━━━━━━━━━━━━━━
ENGAGED (replied / connected): ${engaged.length}
${fmt(engaged)}

ACTIVE IN SEQUENCE: ${active.length}
${fmt(active)}

STALE (${staleThreshold}+ days no activity): ${stale.length}
${fmt(stale)}
━━━━━━━━━━━━━━━━━━━━━

Total tracked: ${contacts.length}
Re-engagement emails will be queued for ${stale.length} stale contacts.

Have a great weekend,
— LeadGen System`;

return [{
  json: {
    to: config.recipient_email,
    subject: `[LeadGen] Friday Pipeline — ${engaged.length} engaged, ${stale.length} stale`,
    body,
    stale_contacts: stale,
    stale_count: stale.length,
    recipient_email: config.recipient_email,
    recipient_name: config.recipient_name
  }
}];

// Parse Claude's re-engagement email array and return for sending
const raw = $json.generated_content || '[]';
let emails = [];

try {
  const m = raw.match(/\[[\s\S]*\]/);
  if (m) emails = JSON.parse(m[0]);
} catch(e) {
  emails = [];
}

const recipient = $json.recipient_email || '';

return emails.map(e => ({
  json: {
    to: recipient, // In production: look up contact email from HubSpot by contact_id
    subject: e.subject || 'Checking back in',
    body: e.body || '',
    contact_id: e.contact_id
  }
}));
